sql:
SELECT AVG(revenue) AS average_earnings, AVG(view_count) AS average_views
FROM episodes
WHERE view_count > (SELECT AVG(view_count) FROM episodes);

SELECT MAX(revenue) AS highest_revenue
FROM episodes
WHERE show_id = 1;

SELECT show_name, average_rating
FROM shows
WHERE average_rating > (SELECT AVG(average_rating) FROM shows);

